sql:
SELECT COUNT(*) AS active_rfq_count
FROM rfqs
WHERE status_id = (SELECT status_id FROM rfq_status WHERE status_name = 'active');

SELECT email
FROM rfq_contacts
WHERE contact_type = 'secondary';

SELECT supplier_id
FROM rfq_responses
WHERE rfq_id = 0;

SELECT rfq_id, SUM(total_cost) AS total_request_cost
FROM rfq_items
GROUP BY rfq_id;

SELECT rfq_id, MAX(file_size) AS largest_attachment_size
FROM rfq_attachments
GROUP BY rfq_id;

SELECT description, total_cost
FROM rfq_items
ORDER BY total_cost DESC;
